import{_ as a,c as s,o,a as t,b as e,d as n}from"./app.2cb13ea6.js";const w='{"title":"Collatz Conjecture","description":"The simplest hardest problem in math history","frontmatter":{"title":"Collatz Conjecture","description":"The simplest hardest problem in math history","editLink":true,"head":[["link",{"rel":"stylesheet","href":"katex.min.css"}]]},"headers":[{"level":2,"title":"The Problem","slug":"the-problem"},{"level":2,"title":"The Person behind the Problem","slug":"the-person-behind-the-problem"},{"level":3,"title":"AC (Ante conjecture)","slug":"ac-ante-conjecture"},{"level":3,"title":"The conjecture","slug":"the-conjecture"},{"level":3,"title":"PC (Post conjecture)","slug":"pc-post-conjecture"},{"level":3,"title":"His books","slug":"his-books"},{"level":2,"title":"Solving the Problem","slug":"solving-the-problem"},{"level":3,"title":"The Plan","slug":"the-plan"},{"level":3,"title":"The Steps (Python)","slug":"the-steps-python"},{"level":3,"title":"The Reality","slug":"the-reality"},{"level":3,"title":"The \\"Solution\\"","slug":"the-solution"},{"level":2,"title":"Sources and Links","slug":"sources-and-links"}],"relativePath":"collatz-conjecture.md","lastUpdated":1655145600000}',l={name:"collatz-conjecture.md"},r=t('<h1 id="collatz-conjecture" tabindex="-1">Collatz Conjecture <a class="header-anchor" href="#collatz-conjecture" aria-hidden="true">#</a></h1><p><strong>The simplest hardest problem in math history</strong></p><p>Last updated on: 2021-12-14</p><hr><div class="info custom-block"><p class="custom-block-title">Jeffery Lagarias, expert on the Collatz conjecture, mathematician at the University of Michigan</p><p>This is a really dangerous problem. People become obsessed with it and it really is impossible.</p></div><div class="info custom-block"><p class="custom-block-title">Paul Erd\xF6s, the man who only loved numbers</p><p>Mathematics is not ready for such problems yet.</p></div><div class="info custom-block"><p class="custom-block-title">Master of alliteration, me</p><p>Many, many mathematicians over the months of meaningless moil have made minimal progress toward the solution of this stupidly simple yet stubbornly unsolvable problem.</p></div><div class="info custom-block"><p class="custom-block-title">Pretty much every mathematician ever</p><p>Don&#39;t waste your time on this.</p></div><p>So, I wasted my time on this.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-hidden="true">#</a></h2><p>So what&#39;s this Collatz conjecture thing? Well, if you haven&#39;t already watched <a href="https://www.youtube.com/watch?v=094y1Z2wpJg" target="_blank" rel="noopener noreferrer">Veritasium&#39;s video</a> about it, then here&#39;s the explanation.</p><ol><li><p>Take a positive whole number.</p></li><li><p>If it&#39;s even, halve it. If it&#39;s odd, multiply it by 3 and add 1.</p></li><li><p>Repeat step 2 until you reach 1.</p></li><li><p>Be confused about what the problem is here.</p></li><li><p>Read explanation below.</p></li></ol><p>The problem here is, we need to find a number that doesn&#39;t eventually reach 1 when you continue this sequence. Why? I have no clue, but it&#39;s an interesting puzzle nonetheless.</p><p>The conjecture suggests that there is no positive whole number that doesn&#39;t eventually reach 1. But that hasn&#39;t been proved (and probably won&#39;t be for a long time), hence why it&#39;s still a conjecture and not a theory.</p><h2 id="the-person-behind-the-problem" tabindex="-1">The Person behind the Problem <a class="header-anchor" href="#the-person-behind-the-problem" aria-hidden="true">#</a></h2><p><a href="https://en.wikipedia.org/wiki/Lothar_Collatz" target="_blank" rel="noopener noreferrer">Lothar Collatz</a> (1910-1990) was a German mathematician born in Arnsberg, Westphalia. He is most known for the Collatz conjecture, even though he did so much more.</p><h3 id="ac-ante-conjecture" tabindex="-1">AC (Ante conjecture) <a class="header-anchor" href="#ac-ante-conjecture" aria-hidden="true">#</a></h3><p>Collatz studied at a total of 4 universities before he got his doctorate. Yes, four.</p><ol><li><p>University of Greifswald</p></li><li><p>Ludwig Maximilian University of Munich</p></li><li><p>University of G\xF6ttingen</p></li><li><p>Humboldt University of Berlin</p><ul><li><p>This is where he studied for his doctorate under <a href="https://de.wikipedia.org/wiki/Alfred_Klose_(Mathematiker)" target="_blank" rel="noopener noreferrer">Alfred Klose</a>, a German mathematician who&#39;s Wikipedia page is only available in German.</p></li><li><p>Collatz was awarded his doctorate in 1935 for his dissertation <strong>Das Differenzenverfahren mit h\xF6herer Approximation f\xFCr lineare Differentialgleichungen</strong> (The finite difference method with higher approximation for linear differential equations).</p></li></ul></li></ol><p>After becoming a non-medical doctor, he worked as an assistant at the University of Berlin, and moved to the Technical University of Karlsruhe later that year.</p><h3 id="the-conjecture" tabindex="-1">The conjecture <a class="header-anchor" href="#the-conjecture" aria-hidden="true">#</a></h3><p>Collatz proposed his conjecture in 1937, just 2 years after being awarded his doctorate.</p><h3 id="pc-post-conjecture" tabindex="-1">PC (Post conjecture) <a class="header-anchor" href="#pc-post-conjecture" aria-hidden="true">#</a></h3><p>From 1938 to 1943 Collatz was a <a href="https://en.wikipedia.org/wiki/Privatdozent" target="_blank" rel="noopener noreferrer">Privatdozent</a> at Karlsruhe. During the good old days of World War II, he worked with <a href="https://en.wikipedia.org/wiki/Alwin_Walther" target="_blank" rel="noopener noreferrer">Alwin Walther</a> at the Institute for Practical Mathematics of the Technische Hochschule Darmstadt.</p><p>In 1943, he was appointed to professorship at the Technical University of Hanover.</p><p>9 years later, in 1952, he moved to the University of Hamburg (the city where the name of hamburgers came from), where, in 1953, he founded the Institute of Applied Mathematics, which is the most original name ever. Collatz worked there until he stopped working, and retired.</p><p>Even after retirement, he was still very active on math conferences, and he died from a heart attack while attending one in Varna, Bulgaria in 1990.</p><h3 id="his-books" tabindex="-1">His books <a class="header-anchor" href="#his-books" aria-hidden="true">#</a></h3><p>This guy wrote a lot of books. The names are all in German and I&#39;m not gonna list them out here, but here&#39;s a list of a few if you want them. I&#39;m sure you can find more online.</p><p><a href="https://en.wikipedia.org/wiki/Lothar_Collatz#Selected_works" target="_blank" rel="noopener noreferrer">Lothar Collatz - Selected works (Wikipedia)</a></p><h2 id="solving-the-problem" tabindex="-1">Solving the Problem <a class="header-anchor" href="#solving-the-problem" aria-hidden="true">#</a></h2><h3 id="the-plan" tabindex="-1">The Plan <a class="header-anchor" href="#the-plan" aria-hidden="true">#</a></h3><p>Back to the topic, how are we gonna solve this problem? We can simplify this problem into 2 expressions:</p>',33),i=e("p",null,[e("span",{class:"katex-display"},[e("span",{class:"katex"},[e("span",{class:"katex-mathml"},[e("math",null,[e("semantics",null,[e("mrow",null,[e("mn",null,"3"),e("mi",null,"x"),e("mo",null,"+"),e("mn",null,"1")]),e("annotation",{encoding:"application/x-tex"},"3x+1 ")])])]),e("span",{class:"katex-html","aria-hidden":"true"},[e("span",{class:"strut",style:{height:"0.64444em"}}),e("span",{class:"strut bottom",style:{height:"0.72777em","vertical-align":"-0.08333em"}}),e("span",{class:"base displaystyle textstyle uncramped"},[e("span",{class:"mord mathrm"},"3"),e("span",{class:"mord mathit"},"x"),e("span",{class:"mbin"},"+"),e("span",{class:"mord mathrm"},"1")])])])])],-1),p=e("p",null,[e("span",{class:"katex-display"},[e("span",{class:"katex"},[e("span",{class:"katex-mathml"},[e("math",null,[e("semantics",null,[e("mrow",null,[e("mfrac",null,[e("mi",null,"x"),e("mn",null,"2")])]),e("annotation",{encoding:"application/x-tex"},"\\frac x 2 ")])])]),e("span",{class:"katex-html","aria-hidden":"true"},[e("span",{class:"strut",style:{height:"1.10756em"}}),e("span",{class:"strut bottom",style:{height:"1.7935600000000003em","vertical-align":"-0.686em"}}),e("span",{class:"base displaystyle textstyle uncramped"},[e("span",{class:"mord reset-textstyle displaystyle textstyle uncramped"},[e("span",{class:"sizing reset-size5 size5 reset-textstyle textstyle uncramped nulldelimiter"}),e("span",{class:"mfrac"},[e("span",{class:"vlist"},[e("span",{style:{top:"0.686em"}},[e("span",{class:"fontsize-ensurer reset-size5 size5"},[e("span",{style:{"font-size":"0em"}},"\u200B")]),e("span",{class:"reset-textstyle textstyle cramped"},[e("span",{class:"mord mathrm"},"2")])]),e("span",{style:{top:"-0.22999999999999998em"}},[e("span",{class:"fontsize-ensurer reset-size5 size5"},[e("span",{style:{"font-size":"0em"}},"\u200B")]),e("span",{class:"reset-textstyle textstyle uncramped frac-line"})]),e("span",{style:{top:"-0.677em"}},[e("span",{class:"fontsize-ensurer reset-size5 size5"},[e("span",{style:{"font-size":"0em"}},"\u200B")]),e("span",{class:"reset-textstyle textstyle uncramped"},[e("span",{class:"mord mathit"},"x")])]),e("span",{class:"baseline-fix"},[e("span",{class:"fontsize-ensurer reset-size5 size5"},[e("span",{style:{"font-size":"0em"}},"\u200B")]),n("\u200B")])])]),e("span",{class:"sizing reset-size5 size5 reset-textstyle textstyle uncramped nulldelimiter"})])])])])])],-1),h=t(`<p>Now that we have those, we can turn it into a program to make the computer do all the work for us. I&#39;m gonna be using Python for this, because it&#39;s one of the easier programming languages to understand and I&#39;m more comfortable with it. If you have a different preference, feel free to use your own preferred language to write the program.</p><h3 id="the-steps-python" tabindex="-1">The Steps (Python) <a class="header-anchor" href="#the-steps-python" aria-hidden="true">#</a></h3><p>Follow these few easy steps and you&#39;ll be on your way to solving this problem in no time:</p><ol><li><p>Download and install <a href="https://www.python.org/" target="_blank" rel="noopener noreferrer">Python (programming language)</a></p></li><li><p>Download and install a code editor. I used <a href="https://atom.io/" target="_blank" rel="noopener noreferrer">Atom</a> and later IDLE (included with Python, would not recommend using) for this, but you can use any code editor you like. If you use an online one, you may not have to install Python at all.</p></li><li><p>Make a new Python program and type in the following code:</p></li></ol><div class="language-py"><span class="copy"></span><pre><code><span class="line"><span style="color:#C792EA;">def</span><span style="color:#EEFFFF;"> </span><span style="color:#82AAFF;">collatz</span><span style="color:#89DDFF;">(</span><span style="color:#EEFFFF;">n</span><span style="color:#89DDFF;">):</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># making the collatz function</span></span>
<span class="line"><span style="color:#EEFFFF;">    </span><span style="color:#89DDFF;font-style:italic;">while</span><span style="color:#EEFFFF;"> n </span><span style="color:#89DDFF;">!=</span><span style="color:#EEFFFF;"> </span><span style="color:#F78C6C;">1</span><span style="color:#89DDFF;">:</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># this tells the code to keep running until it reaches 1</span></span>
<span class="line"><span style="color:#EEFFFF;">        </span><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#EEFFFF;"> n </span><span style="color:#89DDFF;">%</span><span style="color:#EEFFFF;"> </span><span style="color:#F78C6C;">2</span><span style="color:#89DDFF;">:</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># if the number is odd, run code below</span></span>
<span class="line"><span style="color:#EEFFFF;">            n </span><span style="color:#89DDFF;">=</span><span style="color:#EEFFFF;"> n</span><span style="color:#89DDFF;">*</span><span style="color:#F78C6C;">3</span><span style="color:#EEFFFF;"> </span><span style="color:#89DDFF;">+</span><span style="color:#EEFFFF;"> </span><span style="color:#F78C6C;">1</span></span>
<span class="line"><span style="color:#EEFFFF;">        </span><span style="color:#89DDFF;font-style:italic;">else</span><span style="color:#89DDFF;">:</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># else, if the number is even, run code below</span></span>
<span class="line"><span style="color:#EEFFFF;">            n </span><span style="color:#89DDFF;">=</span><span style="color:#EEFFFF;"> n </span><span style="color:#89DDFF;">/</span><span style="color:#EEFFFF;"> </span><span style="color:#F78C6C;">2</span></span>
<span class="line"><span style="color:#EEFFFF;">        </span><span style="color:#82AAFF;">print</span><span style="color:#89DDFF;">(</span><span style="color:#82AAFF;">n</span><span style="color:#89DDFF;">)</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># output number onto screen</span></span>
<span class="line"></span>
<span class="line"><span style="color:#EEFFFF;">num </span><span style="color:#89DDFF;">=</span><span style="color:#EEFFFF;"> </span><span style="color:#FFCB6B;">int</span><span style="color:#89DDFF;">(</span><span style="color:#82AAFF;">input</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Enter a number to test: </span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">))</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># this allows you to put in a different number while running the code instead of having to change the code each time</span></span>
<span class="line"><span style="color:#82AAFF;">collatz</span><span style="color:#89DDFF;">(</span><span style="color:#82AAFF;">num</span><span style="color:#89DDFF;">)</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># run the collatz function with the number you type in</span></span>
<span class="line"><span style="color:#82AAFF;">input</span><span style="color:#89DDFF;">()</span><span style="color:#EEFFFF;"> </span><span style="color:#546E7A;font-style:italic;"># this is there to let you read the output, but otherwise useless to the code</span></span></code></pre></div><p>Alternatively, you can <a href="collatz-conjecture/collatz-conjecture.py" title="Right click and save as to download">download the code here</a>.</p><ol start="4"><li><p>Hit save and double-click the .py file to run it.</p></li><li><p>Enter a number when it tells you to &quot;Enter a number to test: &quot;</p></li><li><p>Wait until the output reaches 1.</p></li><li><p>Realise you&#39;ve wasted possibly hours of your day setting everything up, and writing and rewriting the code, trying to make everything work properly, only to realise that the program only goes up to 2<sup>1024</sup> because there&#39;s something wrong with the code, since Python 3 isn&#39;t supposed to have an integer limit and even though everything had <code>int()</code> around it, it was still working in floats for whatever reason, until you finally remove all the <code>int()</code>s and succumb to the limit that the system has forced upon you.</p></li><li><p>Question the choices you made that brought you to this point in your life.</p></li></ol><p>Seems simple enough, wouldn&#39;t you say?</p><h3 id="the-reality" tabindex="-1">The Reality <a class="header-anchor" href="#the-reality" aria-hidden="true">#</a></h3><p>As you can probably tell, that didn&#39;t end up going too well. No matter what number you put in there, it all seems to go to 1 sooner or later. Don&#39;t worry, that&#39;s a problem that mathematicians of the world have been dealing with for the last 84 years (as of 2021).</p><p>As for my code, I&#39;m sure there&#39;s a much better way to do this than what I&#39;ve written. You can find those online, but I made this program myself, and I&#39;m (kinda) happy with it. There&#39;s probably also a way to automate this so that it tests all the numbers for you, but I liked the idea of being able to try your own numbers to see if they work or not.</p><p>But, if the idea of taking a year off to try every single number up to 2<sup>1024</sup> manually in this program sounds appealing to you, then you really need something exciting in your life, buddy. But other than that, go ahead, give this problem a try. Maybe if you try for long enough, you might find yourself an answer.</p><h3 id="the-solution" tabindex="-1">The &quot;Solution&quot; <a class="header-anchor" href="#the-solution" aria-hidden="true">#</a></h3><p>So far, there&#39;s been no solutions. That&#39;s not really a conclusion since it can&#39;t be proven that there&#39;s no solution. Just like how it can&#39;t be proven that there <strong>is</strong> a solution.</p><p><a href="https://en.wikipedia.org/wiki/Terence_Tao" target="_blank" rel="noopener noreferrer">Terence Tao</a>, kid genius who&#39;s no longer a kid but still a genius, gave this problem a go. He found a &quot;solution&quot;, which is that <strong>almost</strong> all numbers reach 1, which gives us a pretty good estimate of the actual solution. You can read about it in his <a href="https://terrytao.wordpress.com/2011/08/25/the-collatz-conjecture-littlewood-offord-theory-and-powers-of-2-and-3/" target="_blank" rel="noopener noreferrer">blog post</a>. I didn&#39;t understand any of it, but maybe you will.</p><div class="info custom-block"><p class="custom-block-title">Terence Tao, genius, mathematician</p><p>It\u2019s actually an occupational hazard when you\u2019re a mathematician. You could get obsessed with these big famous problems that are way beyond anyone\u2019s ability to touch, and you can waste a lot of time.</p></div><p>I found a thesis by Jose William Porras that claims to be the &quot;Solution to Collatz&#39;s Conjecture&quot;. You can have a read <a href="https://www.researchgate.net/publication/325389892_Solution_to_Collatz&#39;s_Conjecture" target="_blank" rel="noopener noreferrer">here</a>. Again, I didn&#39;t understand it, but maybe you will.</p><h2 id="sources-and-links" tabindex="-1">Sources and Links <a class="header-anchor" href="#sources-and-links" aria-hidden="true">#</a></h2><p><a href="https://www.wikidata.org/wiki/Property:P69" target="_blank" rel="noopener noreferrer">List of universities attended by Lothar Collatz</a></p><p><a href="https://www.quantamagazine.org/mathematician-proves-huge-result-on-dangerous-problem-20191211/" target="_blank" rel="noopener noreferrer">Simpler explanation of Terence Tao&#39;s &quot;solution&quot;</a></p><p><a href="https://en.wikipedia.org/wiki/Collatz_conjecture" target="_blank" rel="noopener noreferrer">Collatz conjecture Wikipedia page</a></p><p><a href="https://mathshistory.st-andrews.ac.uk/Biographies/Collatz/" target="_blank" rel="noopener noreferrer">Lother Collatz biography</a></p><p><a href="https://www.youtube.com/playlist?list=PLPa2dwCo_Eqker6ktrUs7dC7FkKwa7Q2h" target="_blank" rel="noopener noreferrer">YouTube playlist about Collatz conjecture (includes Veritasium video)</a></p><p><strong>All other sources are linked in the main text</strong></p>`,24),c=[r,i,p,h];function u(d,y,m,f,F,b){return o(),s("div",null,c)}var v=a(l,[["render",u]]);export{w as __pageData,v as default};
